@startuml
title BADEXAMPLE's Class Diagram

package "solid" {
    package "interfacesegregation" {
        package "badexample" {
            class AContainer <<C>> {
                +AContainer()
                +doYourContainerStuffToMe()
            }

            class AMachine <<C>> {
                +AMachine()
                +doSomeWork()
            }

            class MUser <<C>> {
                +MUser()
                +doYourOperations()
            }

            class Operations <<C>> {
                +operation1()
                +operation2()
                +operation3()
            }

            ' Note: The original shows aggregation from classes to Operations labeled "ops", 
            ' but this violates Interface Segregation Principle - hence "BADEXAMPLE".
            ' We'll represent exactly what was drawn in the source file for fidelity.
            AContainer o-- Operations : ops
            AMachine o-- Operations : ops  
            MUser o-- Operations : ops

            hide empty methods
        }
    }
}

skinparam backgroundColor white
skinparam defaultFontName Arial
skinparam rectangleStyle rounded=0
@enduml
